partial class ImageLoader
{
    // .NET 9: migrate DllImport to LibraryImport for better AOT/trimming support
    [LibraryImport("shlwapi.dll", EntryPoint = "PathFileExistsW", StringMarshalling = StringMarshalling.Utf16)]
    [return: MarshalAs(UnmanagedType.Bool)]
    private static partial bool PathFileExists(string path);

    void LoadImage(PictureBox pictureBox, string url)
    {
        // .NET 9: PictureBox.Load now uses HttpClient internally
