using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: default StatusStrip rendering changed.
        // Set Professional explicitly to preserve .NET 8 appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }
}

public class MyPropertyEditor : UITypeEditor
{
    public override object? EditValue(
        ITypeDescriptorContext? context, IServiceProvider provider, object? value)
    {
        var svc = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (svc == null) return value;

        using var control = BuildDropDown(value);
        // .NET 9: DropDownControl(null) now throws ArgumentNullException
        if (control != null)
        {
            svc.DropDownControl(control);
            value = control.Tag;
        }
        return value;
    }

    private static Control? BuildDropDown(object? value)
    {
        if (value == null) return null;
        return new ListBox { Tag = value };
    }
}

